  1	import React, { FC, useState } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	
  4	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
  5	import VirtualMachineModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
  6	import ErrorAlert from '@kubevirt-utils/components/ErrorAlert/ErrorAlert';
  7	import { SecretSelectionOption } from '@kubevirt-utils/components/SSHSecretModal/utils/types';
  8	import { createSSHSecret } from '@kubevirt-utils/components/SSHSecretModal/utils/utils';
  9	import { logITFlowEvent } from '@kubevirt-utils/extensions/telemetry/telemetry';
 10	import {
 11	  CANCEL_CUSTOMIZE_VM_BUTTON_CLICKED,
 12	  CUSTOMIZE_VM_FAILED,
 13	  CUSTOMIZE_VM_SUCCEEDED,
 14	} from '@kubevirt-utils/extensions/telemetry/utils/constants';
 15	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 16	import useKubevirtUserSettings from '@kubevirt-utils/hooks/useKubevirtUserSettings/useKubevirtUserSettings';
 17	import { getResourceUrl } from '@kubevirt-utils/resources/shared';
 18	import useNamespaceUDN from '@kubevirt-utils/resources/udn/hooks/useNamespaceUDN';
 19	import { clearCustomizeInstanceType, vmSignal } from '@kubevirt-utils/store/customizeInstanceType';
 20	import { createHeadlessService } from '@kubevirt-utils/utils/headless-service';
 21	import { isEmpty } from '@kubevirt-utils/utils/utils';
 22	import { k8sCreate, useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 23	import {
 24	  Button,
 25	  ButtonVariant,
 26	  Checkbox,
 27	  Split,
 28	  SplitItem,
 29	  Stack,
 30	  StackItem,
 31	} from '@patternfly/react-core';
 32	
 33	import './CustomizeITVMFooter.scss';
 34	
 35	const CustomizeITVMFooter: FC = () => {
 36	  const { t } = useKubevirtTranslation();
 37	  const navigate = useNavigate();
 38	  const [activeNamespace] = useActiveNamespace();
 39	  const [isSubmitting, setIsSubmitting] = useState(false);
 40	  const [error, setError] = useState<any | Error>(null);
 41	  const { instanceTypeVMState, setStartVM, startVM, vm, vmNamespaceTarget } =
 42	    useInstanceTypeVMStore();
 43	
 44	  const [isUDNManagedNamespace] = useNamespaceUDN(activeNamespace);
 45	  const [authorizedSSHKeys, setAuthorizedSSHKeys] = useKubevirtUserSettings('ssh');
 46	  const { sshSecretCredentials } = instanceTypeVMState;
 47	  const { applyKeyToProject, secretOption, sshPubKey, sshSecretName } = sshSecretCredentials || {};
 48	
 49	  return (
 50	    <footer className="customize-it-vm-footer">
 51	      <Stack hasGutter>
 52	        <StackItem>
 53	          <ErrorAlert error={error} />
 54	        </StackItem>
 55	        <StackItem>
 56	          <Checkbox
 57	            id="start-after-create-checkbox"
 58	            isChecked={startVM}
 59	            label={t('Start this VirtualMachine after creation')}
 60	            onChange={(_, checked: boolean) => setStartVM(checked)}
 61	          />
 62	        </StackItem>
 63	        <StackItem />
 64	        <div data-test-id="create-virtual-machine">
 65	          <Split hasGutter>
 66	            <SplitItem>
 67	              <Button
 68	                onClick={async () => {
 69	                  if (
 70	                    applyKeyToProject &&
 71	                    !isEmpty(sshSecretName) &&
 72	                    authorizedSSHKeys?.[vmNamespaceTarget] !== sshSecretName
 73	                  ) {
 74	                    setAuthorizedSSHKeys({
 75	                      ...authorizedSSHKeys,
 76	                      [vmNamespaceTarget]: sshSecretName,
 77	                    });
 78	                  }
 79	                  setIsSubmitting(true);
 80	                  setError(null);
 81	
 82	                  try {
 83	                    const createdVM = await k8sCreate({
 84	                      data: vmSignal.value || vm,
 85	                      model: VirtualMachineModel,
 86	                    });
 87	                    logITFlowEvent(CUSTOMIZE_VM_SUCCEEDED, createdVM);
 88	                    if (secretOption === SecretSelectionOption.addNew) {
 89	                      createSSHSecret(sshPubKey, sshSecretName, vmNamespaceTarget);
 90	                    }
 91	                    clearCustomizeInstanceType();
 92	
 93	                    if (!isUDNManagedNamespace) createHeadlessService(createdVM);
 94	
 95	                    navigate(getResourceUrl({ model: VirtualMachineModel, resource: createdVM }));
 96	                  } catch (err) {
 97	                    setError(err);
 98	                    logITFlowEvent(CUSTOMIZE_VM_FAILED, vm);
 99	                  } finally {
100	                    setIsSubmitting(false);
101	                  }
102	                }}
103	                isLoading={isSubmitting}
104	                variant={ButtonVariant.primary}
105	              >
106	                {t('Create VirtualMachine')}
107	              </Button>
108	            </SplitItem>
109	            <SplitItem>
110	              <Button
111	                onClick={() => {
112	                  logITFlowEvent(CANCEL_CUSTOMIZE_VM_BUTTON_CLICKED, vm);
113	                  clearCustomizeInstanceType();
114	                  navigate(`/k8s/ns/${activeNamespace}/catalog`);
115	                }}
116	                variant={ButtonVariant.link}
117	              >
118	                {t('Cancel')}
119	              </Button>
120	            </SplitItem>
121	          </Split>
122	        </div>
123	      </Stack>
124	    </footer>
125	  );
126	};
127	
128	export default CustomizeITVMFooter;

